// Stage 2 — Normalise
// Handles both webhook JSON and CSV payloads

const items = $input.all();
let records = [];
let source = 'webhook';
const runId = 'RUN-' + new Date().toISOString().slice(0,10).replace(/-/g,'') + '-' + Math.random().toString(36).substr(2,5).toUpperCase();
const startTime = Date.now();

// Determine source and extract records
const firstItem = items[0]?.json;

if (firstItem && firstItem.records && Array.isArray(firstItem.records)) {
  // Webhook payload: { supplier_id, records: [...] }
  records = firstItem.records.map(r => ({ ...r, supplier_id: r.supplier_id || firstItem.supplier_id }));
  source = 'webhook';
} else if (items.length > 0 && (firstItem?.Supplier_ID || firstItem?.supplier_id)) {
  // CSV rows or flat webhook array
  source = items[0]?.json?.Supplier_ID ? 'csv' : 'webhook';

  if (source === 'csv') {
    // Validate CSV headers
    const requiredHeaders = ['Supplier_ID', 'SKU_Code', 'Delivery_Date', 'Weight_KG', 'Lead_Time_Days', 'Origin_Country'];
    const presentHeaders = Object.keys(firstItem);
    const missingHeaders = requiredHeaders.filter(h => !presentHeaders.includes(h));

    if (missingHeaders.length > 0) {
      // Reject entire CSV — missing headers
      return [{
        json: {
          error: true,
          runId: runId,
          startTime: startTime,
          supplier_id: firstItem.Supplier_ID || 'UNKNOWN',
          rejection: 'CSV_HEADER_MISSING',
          missingHeaders: missingHeaders,
          totalRecords: 0,
          cleanRecords: [],
          flaggedRecords: []
        }
      }];
    }

    // Map CSV headers to internal field names
    records = items.map(item => ({
      supplier_id: item.json.Supplier_ID,
      sku_code: item.json.SKU_Code,
      delivery_date: item.json.Delivery_Date,
      weight_kg: item.json.Weight_KG,
      lead_time_days: item.json.Lead_Time_Days,
      origin_country: item.json.Origin_Country
    }));
  } else {
    records = items.map(item => item.json);
  }
}

// Normalise each record
const normalised = [];
const parseErrors = [];

for (const rec of records) {
  const norm = {};

  // supplier_id
  norm.supplier_id = rec.supplier_id ? String(rec.supplier_id).trim() : null;

  // sku_code
  norm.sku_code = rec.sku_code ? String(rec.sku_code).trim() : '';

  // delivery_date — coerce to ISO 8601
  try {
    if (rec.delivery_date) {
      const d = new Date(rec.delivery_date);
      if (isNaN(d.getTime())) throw new Error('Invalid date');
      norm.delivery_date = d.toISOString().slice(0, 10);
    } else {
      norm.delivery_date = null;
    }
  } catch (e) {
    parseErrors.push({
      ...rec,
      record_id: 'REC-' + Math.random().toString(36).substr(2,9).toUpperCase(),
      run_id: runId,
      status: 'flagged',
      flag_reason: 'PARSE_ERROR: delivery_date could not be parsed (value: ' + rec.delivery_date + ')',
      flag_severity: 'LOW'
    });
    continue;
  }

  // weight_kg — coerce to number
  const wRaw = rec.weight_kg;
  const wNum = Number(wRaw);
  if (wRaw !== null && wRaw !== undefined && wRaw !== '' && isNaN(wNum)) {
    parseErrors.push({
      ...rec,
      record_id: 'REC-' + Math.random().toString(36).substr(2,9).toUpperCase(),
      run_id: runId,
      status: 'flagged',
      flag_reason: 'PARSE_ERROR: weight_kg could not be parsed as number (value: ' + wRaw + ')',
      flag_severity: 'LOW'
    });
    continue;
  }
  norm.weight_kg = wNum;

  // lead_time_days — coerce to integer
  const ltRaw = rec.lead_time_days;
  const ltNum = parseInt(ltRaw, 10);
  if (ltRaw !== null && ltRaw !== undefined && ltRaw !== '' && isNaN(ltNum)) {
    parseErrors.push({
      ...rec,
      record_id: 'REC-' + Math.random().toString(36).substr(2,9).toUpperCase(),
      run_id: runId,
      status: 'flagged',
      flag_reason: 'PARSE_ERROR: lead_time_days could not be parsed as integer (value: ' + ltRaw + ')',
      flag_severity: 'LOW'
    });
    continue;
  }
  norm.lead_time_days = ltNum;

  // origin_country
  norm.origin_country = rec.origin_country ? String(rec.origin_country).trim().toUpperCase() : '';

  norm.record_id = 'REC-' + Math.random().toString(36).substr(2,9).toUpperCase();
  norm.run_id = runId;

  normalised.push(norm);
}

return [{
  json: {
    runId: runId,
    startTime: startTime,
    supplier_id: records.length > 0 ? (records[0].supplier_id || 'UNKNOWN') : 'UNKNOWN',
    normalisedRecords: normalised,
    parseErrors: parseErrors,
    totalRecords: records.length
  }
}];

// Stage 3 — Validate
// Apply business rules to each normalised record

const input = $input.first().json;
const { runId, startTime, supplier_id, normalisedRecords, parseErrors, totalRecords } = input;

const cleanRecords = [];
const flaggedRecords = [...parseErrors]; // start with parse errors from Stage 2

const skuPattern = /^[A-Z]{2}[0-9]{6}$/;
const countryPattern = /^[A-Z]{2}$/;
const now = new Date();
const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);

for (const rec of normalisedRecords) {
  const issues = [];

  // Rule 1: delivery_date must be valid ISO 8601 and not more than 90 days in the past
  if (!rec.delivery_date) {
    issues.push({ field: 'delivery_date', reason: 'delivery_date is missing or null', severity: 'HIGH' });
  } else {
    const dd = new Date(rec.delivery_date);
    if (isNaN(dd.getTime())) {
      issues.push({ field: 'delivery_date', reason: 'delivery_date is not a valid ISO 8601 date (value: ' + rec.delivery_date + ')', severity: 'LOW' });
    } else if (dd < ninetyDaysAgo) {
      issues.push({ field: 'delivery_date', reason: 'delivery_date is more than 90 days in the past (value: ' + rec.delivery_date + ')', severity: 'HIGH' });
    }
  }

  // Rule 2: weight_kg must be a positive number greater than zero
  if (rec.weight_kg === null || rec.weight_kg === undefined || isNaN(rec.weight_kg) || rec.weight_kg <= 0) {
    issues.push({ field: 'weight_kg', reason: 'weight_kg must be a positive number greater than zero (value: ' + rec.weight_kg + ')', severity: 'HIGH' });
  }

  // Rule 3: sku_code must match [A-Z]{2}[0-9]{6}
  if (!rec.sku_code || !skuPattern.test(rec.sku_code)) {
    issues.push({ field: 'sku_code', reason: 'sku_code is empty or does not match pattern [A-Z]{2}[0-9]{6} (value: ' + (rec.sku_code || '') + ')', severity: 'LOW' });
  }

  // Rule 4: lead_time_days must be integer 1-14; >14 is CRITICAL
  if (rec.lead_time_days === null || rec.lead_time_days === undefined || isNaN(rec.lead_time_days)) {
    issues.push({ field: 'lead_time_days', reason: 'lead_time_days is missing or not a valid integer', severity: 'HIGH' });
  } else if (rec.lead_time_days < 1) {
    issues.push({ field: 'lead_time_days', reason: 'lead_time_days must be at least 1 (value: ' + rec.lead_time_days + ')', severity: 'HIGH' });
  } else if (rec.lead_time_days > 14) {
    issues.push({ field: 'lead_time_days', reason: 'lead_time_days exceeds 14-day SLA limit (value: ' + rec.lead_time_days + ')', severity: 'CRITICAL' });
  }

  // Rule 5: origin_country must be 2-char ISO 3166-1 alpha-2
  if (!rec.origin_country || !countryPattern.test(rec.origin_country)) {
    issues.push({ field: 'origin_country', reason: 'origin_country is not a valid ISO 3166-1 alpha-2 code (value: ' + (rec.origin_country || '') + ')', severity: 'MEDIUM' });
  }

  // Rule 6: supplier_id must be present and non-null
  if (!rec.supplier_id) {
    issues.push({ field: 'supplier_id', reason: 'supplier_id is missing or null', severity: 'HIGH' });
  }

  if (issues.length > 0) {
    // Take the highest severity
    const severityOrder = { 'CRITICAL': 4, 'HIGH': 3, 'MEDIUM': 2, 'LOW': 1 };
    issues.sort((a, b) => (severityOrder[b.severity] || 0) - (severityOrder[a.severity] || 0));
    const highestSeverity = issues[0].severity;
    const allReasons = issues.map(i => i.reason).join('; ');

    flaggedRecords.push({
      ...rec,
      status: 'flagged',
      flag_reason: allReasons,
      flag_severity: highestSeverity,
      flagged_fields: issues
    });
  } else {
    cleanRecords.push({
      ...rec,
      status: 'clean',
      flag_reason: null,
      flag_severity: null
    });
  }
}

return [{
  json: {
    runId: runId,
    startTime: startTime,
    supplier_id: supplier_id,
    totalRecords: totalRecords,
    cleanRecords: cleanRecords,
    flaggedRecords: flaggedRecords,
    hasCritical: flaggedRecords.some(r => r.flag_severity === 'CRITICAL'),
    error: input.error || false,
    rejection: input.rejection || null
  }
}];

// Merge enrichment data back into the records

const input = $input.first().json;
const enrichResult = $node['Enrich Supplier Lookup'].json;

const supplierName = enrichResult?.supplier_name || input.supplier_id;
const supplierRegion = enrichResult?.region || 'Unknown';

// Append supplier info to all clean records
const enrichedClean = (input.cleanRecords || []).map(r => ({
  ...r,
  supplier_name: supplierName,
  supplier_region: supplierRegion
}));

const enrichedFlagged = (input.flaggedRecords || []).map(r => ({
  ...r,
  supplier_name: supplierName,
  supplier_region: supplierRegion
}));

const duration = Date.now() - input.startTime;

return [{
  json: {
    ...input,
    supplier_name: supplierName,
    cleanRecords: enrichedClean,
    flaggedRecords: enrichedFlagged,
    duration_ms: duration
  }
}];

// Stage 5 — Prepare individual record inserts

const input = $input.first().json;
const allRecords = [...(input.cleanRecords || []), ...(input.flaggedRecords || [])];

if (allRecords.length === 0) {
  return [{ json: { ...input, recordsStored: 0 } }];
}

// Build parameterised VALUES
const values = allRecords.map(r => {
  const rid = r.record_id || ('REC-' + Math.random().toString(36).substr(2,9).toUpperCase());
  const sku = (r.sku_code || '').replace(/'/g, "''");
  const dd = r.delivery_date || null;
  const wkg = r.weight_kg !== undefined && r.weight_kg !== null ? r.weight_kg : 'NULL';
  const lt = r.lead_time_days !== undefined && r.lead_time_days !== null ? r.lead_time_days : 'NULL';
  const oc = (r.origin_country || '').replace(/'/g, "''");
  const st = r.status || 'clean';
  const fr = r.flag_reason ? r.flag_reason.replace(/'/g, "''") : null;
  const fs = r.flag_severity || null;

  return `('${rid}', '${input.runId}', '${r.supplier_id}', '${sku}', ${dd ? "'" + dd + "'" : 'NULL'}, ${wkg}, ${lt}, '${oc}', '${st}', ${fr ? "'" + fr + "'" : 'NULL'}, ${fs ? "'" + fs + "'" : 'NULL'})`;
}).join(',\n');

return [{
  json: {
    ...input,
    insertQuery: `INSERT INTO pipeline_records (record_id, run_id, supplier_id, sku_code, delivery_date, weight_kg, lead_time_days, origin_country, status, flag_reason, flag_severity) VALUES ${values}`,
    recordsStored: allRecords.length
  }
}];

