// Error handler — check for DB failures and set error response
const input = $input.first().json;

// If we got here via continueOnFail from a Postgres node
if (input.error || input.errorMessage) {
  return [{
    json: {
      httpStatus: 500,
      errorMessage: 'Database write failed: ' + (input.errorMessage || 'Unknown error'),
      runId: input.runId || 'UNKNOWN'
    }
  }];
}

return [{ json: input }];
